  const { t } = useTranslation('common');
  const { showToast } = useToast();
  const { createSession, isLoading } = useDonorSession();
  const { getValues } = useFormContext<LoginFormData>();

  const onSubmit = useCallback(
    (e) => {
      e.preventDefault();
      e.stopPropagation();
      const { password, username: email } = getValues();

      createSession(email, password)
        .then(() => onSuccess())
        .catch((message) =>
          showToast({
            message,
            variant: 'error',
          })
        );
    },
    [createSession, getValues, onSuccess, showToast]
  );

